module FixedPriorityArbiter(  
    input wire clk,  
    input wire rst,  
    input wire req0,  
    input wire req1,  
    input wire req2,  
    input wire req3,  
    output reg grant  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst) begin  
            grant <= 0;  
        end  
        else begin  
            if (req0) grant <= 4'b0001;  
            else if (req1) grant <= 4'b0010;  
            else if (req2) grant <= 4'b0100;  
            else if (req3) grant <= 4'b1000;  
            else grant <= 0;  
        end  
    end  
endmodule
